const body = $input.first().json.body ?? $input.first().json;
const {
  seq_step_id, patient_id, doctor_id, doctor_name,
  scheduled_date, scheduled_time, duration_minutes,
  notes, google_calendar_id
} = body;

if (!seq_step_id)    throw new Error('seq_step_id is required');
if (!patient_id)     throw new Error('patient_id is required');
if (!doctor_id)      throw new Error('doctor_id is required');
if (!scheduled_date) throw new Error('scheduled_date is required');
if (!scheduled_time) throw new Error('scheduled_time is required (HH:mm)');

const dur = parseInt(duration_minutes, 10);
if (!dur || dur < 1) throw new Error('duration_minutes must be > 0');

// Validate time format HH:mm
if (!/^\d{2}:\d{2}$/.test(scheduled_time)) throw new Error('scheduled_time must be HH:mm');

return [{ json: {
  seq_step_id:        parseInt(seq_step_id, 10),
  patient_id,
  doctor_id,
  doctor_name:        doctor_name || null,
  scheduled_date,
  scheduled_time,
  duration_minutes:   dur,
  notes:              notes || null,
  google_calendar_id: google_calendar_id || null,
} }];

const rows = $input.all();
if (rows.length === 0) throw new Error('treatment_seq_steps row not found');
const step = rows[0].json;
if (step.appointment_id) throw new Error('Step already has a linked appointment');

const parse = $('Parse Input').first().json;

// Build start datetime from date + time
const startDt = `${parse.scheduled_date}T${parse.scheduled_time}:00`;

// Compute end datetime
const endDt = (() => {
  const d = new Date(startDt);
  d.setMinutes(d.getMinutes() + parse.duration_minutes);
  return d.toISOString().slice(0, 19);
})();

const doctorLabel = parse.doctor_name ? parse.doctor_name : `Doctor ${parse.doctor_id.slice(0, 8)}`;
const summary = `Paso ${step.step_position}: ${step.step_name} — ${doctorLabel}`;

const calendarSourceSQL = parse.google_calendar_id
  ? `SELECT id AS calendar_source_id FROM calendar_sources WHERE google_calendar_id = '${parse.google_calendar_id}' LIMIT 1`
  : `SELECT NULL::bigint AS calendar_source_id`;

return [{ json: {
  ...parse,
  seq_step_id:   step.id,
  sequence_id:   step.sequence_id,
  step_name:     step.step_name,
  step_position: step.step_position,
  startDt,
  endDt,
  summary,
  calendarSourceSQL,
} }];

const calRow = $input.all()[0]?.json;
const calSourceId = calRow?.calendar_source_id || null;
const build = $('Validate + Build Data').first().json;

const notesVal   = build.notes ? `'${build.notes.replace(/'/g, "''")}'` : 'NULL';
const summaryVal = `'${build.summary.replace(/'/g, "''")}'`;
const calVal     = calSourceId ? calSourceId : 'NULL';

const insertSQL = `
  INSERT INTO appointments (
    patient_id, assignee_id, start_datetime, end_datetime,
    summary, notes, status, treatment_seq_step_id, calendar_source_id
  ) VALUES (
    '${build.patient_id}', '${build.doctor_id}',
    '${build.startDt}', '${build.endDt}',
    ${summaryVal}, ${notesVal},
    'scheduled', ${build.seq_step_id}, ${calVal}
  )
  RETURNING id::text AS appointment_id
`;

return [{ json: { ...build, calSourceId, insertSQL } }];

const rows = $input.all().filter(r => r.json.id);
if (rows.length === 0) throw new Error('Failed to link appointment to step');
const r = rows[0].json;
return [{ json: {
  success: true,
  appointment_id: r.appointment_id,
  step: {
    id: r.id,
    step_number: r.step_number,
    step_name: r.step_name,
    scheduled_date: r.scheduled_date || null,
    appointment_id: r.appointment_id,
    status: 'scheduled',
    notes: r.notes || null,
    duration_minutes: r.duration_minutes || null,
    completed_at: null,
  },
} }];
